### **方法四：Lambda 表达式**

C++11 提供的 Lambda 表达式非常灵活，尤其适合竞赛或临时需求的场景。

#### **最小堆实现**
```cpp
#include <queue>
#include <vector>
#include <iostream>
using namespace std;

int main() {
    auto compare = [](int a, int b) { return a > b; }; // 最小堆
    priority_queue<int, vector<int>, decltype(compare)> minHeap(compare);

    minHeap.push(3);
    minHeap.push(1);
    minHeap.push(5);

    while (!minHeap.empty()) {
        cout << minHeap.top() << " "; // 输出：1 3 5
        minHeap.pop();
    }
    return 0;
}
```

#### **复杂数据类型排序**
```cpp
#include <queue>
#include <vector>
#include <iostream>
using namespace std;

struct Point {
    int x, y;
    Point(int x, int y) : x(x), y(y) {}
};

int main() {
    auto compare = [](const Point& p1, const Point& p2) {
        if (p1.x == p2.x) return p1.y < p2.y; // 按 y 降序排列
        return p1.x > p2.x; // 否则按 x 升序排列
    };

    priority_queue<Point, vector<Point>, decltype(compare)> pq(compare);

    pq.push(Point(1, 10));
    pq.push(Point(2, 5));
    pq.push(Point(1, 20));

    while (!pq.empty()) {
        Point p = pq.top();
        cout << "(" << p.x << ", " << p.y << ")" << endl;
        pq.pop();
    }
    return 0;
}
```

#### **输出：**
```
(1, 20)
(1, 10)
(2, 5)
```

