#### 题目1.[[USACO2.4] 牛的旅行 Cow Tours](https://www.luogu.com.cn/problem/P1522)
- **解题方法**：Floyd+连通块+枚举(不用连通块会被hack一个点)
- **遇到的问题**：输入问题,以后再也不这样处理输入了,找了半天都不知道哪里错了
- **解决方案**：
```cpp:line-numbers
#include <bits/stdc++.h>
#define int long long // 自觉去掉，当需要 memset 数组为 0x3f 时使用
#define INF 1e20
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 5 * 1e3 + 10;

int n;
int block[M];
PII node[M];
char g[M][M];
double dist[M][M],maxd[M],blockd[M];
void Floyd() {
    for (int k = 1; k <= n; k++) 
        for (int i = 1; i <= n; i++)
            for (int j = 1; j <= n; j++)
                dist[i][j] = min(dist[i][j],dist[i][k]+dist[k][j]);
}
void dfs(int u,int id) {
    block[u] = id;
    for (int i = 1; i <= n; i++) {
        if (!block[i] && dist[u][i] < INF) {
            dfs(i,id);
        }
    }
}
void solve() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        int x, y;
        cin >> x >> y;
        node[i] = {x,y};
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            cin >> g[i][j];
        }
    }

    auto getdist = [](const PII &a, const PII &b) {
        auto [x1, y1] = a; auto [x2, y2] = b;
        return sqrt(pow(x1 - x2, 2) + pow(y1 - y2, 2));
    };

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (i != j) {
                if (g[i][j] == '1') dist[i][j] = getdist(node[i], node[j]);
                else dist[i][j] = INF;
            }else dist[i][j] = 0;
        }
    }

    Floyd();

    int id = 0;
    for (int i = 1; i <= n; i++) {
        if(!block[i]) dfs(i,++id);
    }

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (dist[i][j] < INF) {
                maxd[i] = max(maxd[i],dist[i][j]);
            }
        }
    }

    for (int i = 1; i <= id; i++) {
        double maxx = -INF;
        for (int j = 1; j <= n; j++) {
            if (block[j] == i) {
                maxx = max(maxx,maxd[j]);
            }
        }
        blockd[i] = maxx;
    }

    double res = INF;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (block[i] != block[j]) {
                res = min(res, max(getdist(node[i], node[j]) + maxd[i] + maxd[j], max(blockd[block[i]], blockd[block[j]]))) ;
            }
        }
    }

    printf("%lf",res);
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

