using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 5 * 1e3 + 10;


int n, m;
bool g[M][M], d[M][M];
bool st[M];
void Floyd() {
    memcpy(d,g,sizeof g);
    for (int k = 0; k < n; k ++) 
        for (int i = 0; i < n; i++)
            for (int j = 0; j < n; j++)
                d[i][j] = d[i][j] | (d[i][k] && d[k][j]);
}
int check() {
    for (int i = 0; i < n; i++) {
        if(d[i][i]) return 2;
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (!d[i][j] && !d[j][i]) return 0;
        }
    }

    return 1;
}
char getmin() {
    for (int i = 0; i < n; i++) {
        if(st[i]) continue;
        bool f = 1;
        for (int j = 0; j < n; j++) {
            if (!st[j] && d[j][i]) {
                f = 0;
                break;
            }
        }
        if (f) {st[i] = 1; return i + 'A';}
    }
}
void solve() {
    cin >> n >> m;
    int x,type = 0;
    for (int i = 1; i <= m; i++) {
        string s;
        cin >> s;
        if(type) continue;
        g[s[0] - 'A'][s[2] - 'A'] = 1;
        Floyd();
        type = check();
        if (type) x = i;
    }    

    if (type == 0) printf("Sorted sequence cannot be determined.\n");
    else if (type == 2) printf("Inconsistency found after %d relations.\n",x);
    else {
        printf("Sorted sequence determined after %d relations: ",x);
        for (int i = 0; i < n; i++) printf("%c",getmin());
        printf(".\n");
    }
}

