using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 5 * 1e3 + 10;

int n, m, ass;
int in[30];
set<int> st;
bool vis[30];
map<PII,int> mp;
vector<int> G[M];
vector<char> ans;
int topsort() {
    queue<PII> q;
    ans.clear();
    int tin[30];
    memcpy(tin,in,sizeof in);
    int cnt = 0;
    for (int i = 0; i < n; i++) 
        if (!tin[i] && vis[i]) q.emplace(i,1), cnt++ , ans.push_back(i + 'A');
    while (q.size()) {
        auto [u,val] = q.front();
        q.pop();
        for (int v : G[u]) {
            if (-- tin[v] == 0) {
                cnt ++;
                ans.push_back(v + 'A');
                q.emplace(v,val+1);
                ass = max(ass,val+1);
            }
        }
    }

    if (ass == n) return 1;
    else if (cnt != st.size()) return 2;
    return 0;
}
void solve() {
    cin >> n >> m;
    int type = 0, x;
    for (int i = 1; i <= m; i++) {
        string s;
        cin >> s;
        int a = s[0] - 'A' , b = s[2] - 'A';
        vis[a] = vis[b] = 1;
        st.insert(a), st.insert(b);
        if(!mp.count({a,b})) G[a].emplace_back(b);
        else mp[{a,b}] = 1;
        in[b] ++;
        if (!type) {
            type = topsort();
            if (type) x = i;
        }
    }

    if (type == 2) printf("Inconsistency found after %d relations.",x);
    else if (type == 0) printf("Sorted sequence cannot be determined.");
    else {
        printf("Sorted sequence determined after %d relations: ",x);
        for (auto c : ans) printf("%c",c);
        printf(".");
    }
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
