#### 题目4.[[USACO07NOV] Cow Relays G](https://www.luogu.com.cn/problem/P2886)
- **解题方法**：矩阵乘法 + DP(Floyd)
- **解决方案**：
```cpp:line-numbers
#include <bits/stdc++.h>
// #define int long long // 自觉去掉，当需要 memset 数组为 0x3f 时使用
#define INF 0x3f3f3f3f
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 200 + 10;

int k, n, T, S, E;
int g[M][M], res[M][M];
unordered_map<int, int> mp;
void mul(int c[][M],int a[][M],int b[][M]) {
    static int temp[M][M];
    memset(temp, 0x3f, sizeof temp);

    for (int k = 1; k <= n; k ++) 
        for (int i = 1; i <= n; i ++) 
            for (int j = 1; j <= n; j ++) 
                temp[i][j] = min(temp[i][j], a[i][k] + b[k][j]);

    memcpy(c, temp, sizeof temp);
}
void qmi() {
    memset(res, 0x3f, sizeof res);
    for (int i = 1; i <= n; i++) res[i][i] = 0;

    while(k) {
        if (k & 1) mul(res, res, g);
        mul(g, g, g);
        k >>= 1;
    }
}
void solve() {
    cin >> k >> T >> S >> E;

    memset(g, 0x3f, sizeof g);

    mp[S] = ++ n;
    mp[E] = ++ n;
    S = mp[S], E = mp[E];

    while (T--) {
        int w, u, v;
        cin >> w >> u >> v;
        if (!mp.count(u)) mp[u] = ++ n;
        if (!mp.count(v)) mp[v] = ++ n;
        u = mp[u], v = mp[v];
        g[u][v] = g[v][u] = min(g[u][v], w);
    }

    qmi();

    cout << res[S][E] << '\n';
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

