#### 题目7.[北极通讯网络](https://www.dotcpp.com/oj/problem2396.html)
- **解题方法**：DFS求连通块个数 + 二分答案 或 Kruskal
- **解决方案**：
> DFS求连通块个数 + 二分答案
```cpp:line-numbers
#include <bits/stdc++.h>
// #define int long long // 仅在需要大整数时使用，memset 数组为 0x3f 时去掉
#define INF 0x3f3f3f3f
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 5 * 1e2 + 10;

int n, k;
int block[M];
vector<PII> axis;
vector<pair<int,double>> G[M];

void dfs(int id,int u,double d) {
    block[u] = id;
    for (auto [v, w] : G[u]) {
        if (!block[v] && w <= d) dfs(id, v, d);
    }
}
void build() {
    auto get_dist = [](const PII &a, const PII &b) {
        return sqrt(pow(a.first - b.first, 2) + pow(a.second - b.second, 2));
    };
    for (int i = 0; i < n; i ++) 
        for (int j = i + 1; j < n; j ++) 
            G[i].emplace_back(j, get_dist(axis[i], axis[j])), G[j].emplace_back(i, get_dist(axis[i], axis[j]));
}
bool check(double d) {
    memset(block, 0, sizeof block);
    int cnt = 0;
    for (int i = 0; i < n; i ++)
        if (!block[i]) dfs(++cnt ,i, d);

    return cnt <= k;
}
void solve() {
    cin >> n >> k;
    for (int i = 0; i < n; i ++) {
        int x, y;
        cin >> x >> y;
        axis.emplace_back(x, y);
    }

    build();

    double l = 0, r = 1e18;
    while (fabs(l - r) > 1e-6) {
        double mid = (l + r) / 2;
        if (check(mid)) r = mid;
        else l = mid;
    }

    printf("%.2lf\n",l);
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

