constexpr int N = 1 * 1e6 + 10, M = 5 * 1e3 + 10;


void solve() {
    int a, b;
    cin >> a >> b;
    if (b == 1) {
        cout << a * 1000;
        return;
    }
    double l = 0, r = 1e18;
    while (abs(l - r) > 1e-11) {
        double mid = (l + r) / 2;
        if(pow(mid, b) <= a) l = mid;
        else r = mid;
    }

    cout << int(l * 1000);
