#### 题目1.[神经网络](https://www.lanqiao.cn/problems/748/learning/)
- **解题方法**：拓扑排序
- **遇到的问题**：我以为非输入层就是输出层,在输入数据时就判了,非活动层的权值*阈值也加上了
- **解决方案**：非输入层!=输出层,节点后没有子节点的才是输出层
![](/posts/备战传智蓝桥DAY-2_2025-02-08-20-25-53.png)
```cpp:line-numbers
#include<bits/stdc++.h>
#define int long long
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10,inf = 0x3f3f3f3f;

int n,p;
int U[N],in[N],C[N];
bool isout[N];
struct edge
{
    int to,w;
};
vector<edge> G[M];
void solve()
{
    cin >> n >> p;
    queue<int> q;
    for(int i=1;i<=n;i++)
    {
        cin >> C[i] >> U[i];
    }
    for(int i=1;i<=p;i++)
    {
        int u,v,w;
        cin >> u >> v >> w;
        G[u].push_back({v,w});
        in[v] ++;
    }
    for(int i=1;i<=n;i++)
    {
        if(!in[i])
        {
            q.push(i);
            U[i] = 0;
        }
        if(G[i].size() == 0) isout[i] = true;
    }
    while(q.size())
    {
        int u = q.front();
        q.pop();
        for(auto [v,w] : G[u])
        {
            if(C[u] > 0)
            C[v] += w * C[u];
            if(--in[v] == 0)
            {
                C[v] -= U[v];
                q.push(v);
            }
        }
    }
    bool f = false;
    for(int i=1;i<=n;i++)
    {
        if(C[i] > 0 && isout[i]) {
            cout << i << ' ' << C[i] << '\n';
            f = true;
        }
    }
    if(!f) cout << "NULL";
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
