```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

typedef pair<double,int> PDI;

int n;
double m;
double dist[N];
bool st[N];
int path[N];
struct node
{
    double x,y,z;
};
vector<pair<int,double>> G[N];
void Dijkstra()
{
    fill(dist , dist+ n + 10 , 1e18);
    memset(path,-1,sizeof path);
    priority_queue<PDI,vector<PDI>,greater<PDI>> heap;
    dist[0] = 0;
    heap.push({0,0});
    while(heap.size())
    {
        auto [d,u] = heap.top();
        heap.pop();
        if(st[u]) continue;
        st[u] = 1;
        for(auto [v,w] : G[u])
        {
            if(dist[u] + w < dist[v] && w <= m)
            {
                dist[v] = dist[u] + w;
                path[v] = u;
                heap.push({dist[v],v});
            }
        }
    }
    if(dist[n+1] == 1e18) printf("-1\n");
    else
    {
        auto getpath = [](){
            vector<int> t;
            for(int i=n+1;~i;i=path[i]){
                t.push_back(i);
            }
            reverse(all(t));
            return t;
        };
        auto p = getpath();
        printf("%.3lf\n",dist[n+1]);
        for(auto x : p)
        {
            if(x == 0) printf("Start ");
            else if(x == n+1) printf("End");
            else printf("%d ",x);
        }
    }
}
void solve()
{
    double x1,y1,z1,x2,y2,z2;
    cin >> n >> m;
    cin >> x1 >> y1 >> z1 >> x2 >> y2 >> z2;
    vector<node> point;
    point.push_back({x1,y1,z1});
    for(int i=1;i<=n;i++)
    {
        double a,b,c;
        cin >> a >> b >> c;
        point.push_back({a,b,c});
    }
    point.push_back({x2,y2,z2});
    auto dis = [](double x1,double x2,double y1,double y2,double z1,double z2){
        return sqrt(pow(x1-x2,2) + pow(y1-y2,2) + pow(z1-z2,2));
    };
    for(int i=0;i<point.size();i++)
    {
        for(int j=0;j<point.size();j++)
        {
            if(i == j) continue;
            auto [x1,y1,z1] = point[i];
            auto [x2,y2,z2] = point[j];
            G[i].push_back({j,dis(x1,x2,y1,y2,z1,z2)});
        }
    }

    Dijkstra();
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

