    for(int i=0;i<m;i++)
    {
        int a,b,c,d;
        cin >> a >> b >> c >> d;
        if(d == 1)
        {
            G[a].push_back({b+n,c});
            G[b].push_back({a+n,c});
            G[a+n].push_back({b+n+n,c});
            G[b+n].push_back({a+n+n,c});
        }
        else
        {
            G[a].push_back({b,c});
            G[b].push_back({a,c});
            G[a+n].push_back({b+n,c});
