- **解题方法**：map存储坐标的一维起点对上一维终点和花费,就是int->pair<int,int>,分两种情况更新
- **遇到的问题**：走到传送门还会消耗一点能量,而不是直接上去直接就传走了而不收你费了,开始没加,还让我调了一会儿
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

typedef pair<int,PII> PIPii;
int n,m,k,E;
int sx,sy,ex,ey;
char g[M][M];
bool st[M][M];
int dist[M][M];
int dir[4][2] = {{1,0},{0,1},{-1,0},{0,-1}};
unordered_map<int,PII> mp;
int dijkstra()
{
    memset(dist,0x3f,sizeof dist);
    priority_queue<PIPii,vector<PIPii>,greater<PIPii>> heap;
    heap.push({0,{sx,sy}});
    dist[sx][sy] = 0; 
    while(heap.size())
    {
        auto [d,p] = heap.top();
        heap.pop();
        auto [x,y] = p;
        if(st[x][y]) continue;
        st[x][y] = 1;
        for(int i=0;i<4;i++)
        {
            int nx = x + dir[i][0], ny = y + dir[i][1];
            if(nx > n || ny > m || nx <= 0 || ny <= 0) continue;
            if(g[nx][ny] == '#') continue;
            int one = (nx - 1) * m + ny;
            if(dist[x][y] + 1 < dist[nx][ny])
            {
                dist[nx][ny] = dist[x][y] + 1;
                heap.push({dist[nx][ny],{nx,ny}});
            }
            if(mp.count(one))
            {
                int w = mp[one].second + 1; // [!code warning]
                int cx = (mp[one].first - 1) / m + 1 , cy = (mp[one].first - 1) % m + 1;
                if(dist[x][y] + w < dist[cx][cy])
                {
                    dist[cx][cy] = dist[x][y] + w;
                    heap.push({dist[cx][cy],{cx,cy}});
                }
            }
        }
    }

    if(E - dist[ex][ey] < 0) return -1;
    return E - dist[ex][ey];
}
void solve()
{
    cin >> n >> m;
    cin >> sx >> sy >> ex >> ey;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            cin >> g[i][j];
    cin >> k;
    for(int i=0;i<k;i++)
    {
        int x1,y1,x2,y2,p;
        cin >> x1 >> y1 >> x2 >> y2 >> p;
        mp[(x1 - 1) * m + y1] = {(x2 - 1) * m + y2 , p};
    }
    cin >> E;

    cout << dijkstra() << '\n';
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

