#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

int n,m,k;
int dp[M][M];
vector<PII> G[M];
void Dijkstra()
{
    memset(dp,0x3f,sizeof dp);
    queue<int> q;
    q.push(0);
    dp[0][0] = 0;
    while(q.size())
    {
        int u = q.front();
        q.pop();
        for(auto [v,w] : G[u])
        {
            bool flag = 0;
            if(dp[u][0] + w < dp[v][0])
            {
                dp[v][0] = dp[u][0] + w;
                flag = 1;
            }

            for(int i=1;i<=k;i++)
            {
                if(dp[u][i-1] < dp[v][i])
                {
                    dp[v][i] = dp[u][i-1];
                    flag = 1;
                }
            }

            if(dp[u][k] + w < dp[v][k])
            {
                dp[v][k] = dp[u][k] + w;
                flag = 1;
            }

            if(flag) q.push(v);
        }
    }
}
void solve()
{
    cin >> n >> k >> m;
    for(int i=0;i<m;i++)
    {
        int u,v,w;
        cin >> u >> v >> w;
        G[u].push_back({v,w});
        G[v].push_back({u,w});
    }
    Dijkstra();
    cout << min(dp[n-1][0],dp[n-1][k]);
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
