#### 题目4.[信息学奥赛一本通T1503-道路和航线](https://www.dotcpp.com/oj/problem2412.html)
- **解题方法**：dfs求连通块+拓扑排序+Dijkstra
- **遇到的问题**：开始以为用SPFA就行,果不其然,卡掉了两个,看了题解又学到了,Dijkstra也可以求负权图的最短路😋
- **解决方案**：
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

int t,r,p,s;
int ku;
int dist[N],in[N],cnt[N];
bool vis[N];
vector<PII> G[N];
vector<int> bo[N];
queue<int> topp;
void dfs(int u,int ko)
{
    cnt[u] = ko;
    bo[ko].push_back(u);
    for(auto [v,_] : G[u])
    {
        if(cnt[v]) continue;
        dfs(v,ko);
    }
}
void Dijkstra(int st)
{
    priority_queue<PII,vector<PII>,greater<PII>> heap;
    for(int u : bo[st]) heap.push({dist[u],u});
    while(heap.size())
    {
        auto [d,u] = heap.top();
        heap.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v,w] : G[u])
        {
            if(cnt[v] != cnt[u] && --in[cnt[v]] == 0)
            {
                topp.push(cnt[v]);
            }
            if(dist[u] + w < dist[v])
            {
                dist[v] = dist[u] + w;
                if(cnt[u] == cnt[v]) heap.push({dist[v],v});
            }
        }
    }
}
void topsort()
{
    memset(dist,0x3f,sizeof dist);
    dist[s] = 0;
    for(int i=1;i<=ku;i++)
    {
        if(!in[i]) topp.push(i);
    }
    while(topp.size())
    {
        int u = topp.front();
        topp.pop();
        Dijkstra(u);
    }
}
void solve()
{
    cin >> t >> r >> p >> s;
    int a,b,c;
    for(int i=0;i<r;i++)
    {
        cin >> a >> b >> c;
        G[a].push_back({b,c});
        G[b].push_back({a,c});
    }
    for(int i=1;i<=t;i++)
    {
        if(!cnt[i]) dfs(i,++ku);
    }
    for(int i=0;i<p;i++)
    {
        cin >> a >> b >> c;
        G[a].push_back({b,c});
        in[cnt[b]] ++;
    }
    topsort();
    for(int i=1;i<=t;i++)
    {
        if(dist[i] > INF / 2) cout << "NO PATH\n";
        else cout << dist[i] << '\n';
    }
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

