#### 题目5.[会面](https://www.lanqiao.cn/problems/4218/learning/)
- **解题方法**：枚举每个中间会面点就行,求两段路(起点到会面点,会面点到终点)的最大值加起来更新最小的答案就行
- **解决方案**：
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

int n,m;
int dis[M][M];
void init()
{
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(i == j) dis[i][j] = 0;
            else dis[i][j] = INF;
        }
    }
}
void floyd()
{
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                dis[i][j] = min(dis[i][j],dis[i][k]+dis[k][j]);
            }
        }
    }
}
void solve()
{
    cin >> n >> m;
    init();
    for(int i=0;i<m;i++)
    {
        int u,v,w;
        cin >> u >> v >> w;
        dis[u][v] = min(dis[u][v],w);
        dis[v][u] = min(dis[v][u],w);
    }
    int s1,e1,s2,e2;
    cin >> s1 >> e1 >> s2 >> e2;
    floyd();
    int time = INF;
    for(int i=1;i<=n;i++)
    {
        time = min(max(dis[s1][i],dis[s2][i]) + max(dis[i][e1],dis[i][e2]), time);
    }
    if(time == INF) cout << -1;
    else cout << time;
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

