```cpp
bool isOnEdge(int x1, int y1, int x2, int y2, int px, int py) {
    // 规范矩形的坐标范围，确保 (x1, y1) 是左下角，(x2, y2) 是右上角
    if (x1 > x2) swap(x1, x2);
    if (y1 > y2) swap(y1, y2);

    // 检查是否在矩形边上
    return (
        (py == y1 && px >= x1 && px <= x2) ||  // 在上边
        (py == y2 && px >= x1 && px <= x2) ||  // 在下边
        (px == x1 && py >= y1 && py <= y2) ||  // 在左边
        (px == x2 && py >= y1 && py <= y2)     // 在右边
    );
}
