#### 题目2.[地铁最短路径与最少换乘](https://www.lanqiao.cn/problems/4556/learning/)
- **解题方法**：DIjkstra + BFS
- **遇到的问题**：最短路径都忘了要用BFS了,DFS调了半天,才记起还有BFS
- **解决方案**：
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e5 + 10,M = 2 * 1e5 + 10;

int n,m;
int ans = INF;
int dist[N];
bool vis[N];
vector<PII> G[M];
int Dijkstra(int st,int ed)
{
    memset(dist,0x3f,sizeof dist);
    priority_queue<PII,vector<PII>,greater<PII>> heap;
    heap.push({0,st});
    dist[st] = 0;
    while(heap.size())
    {
        auto [_,u] = heap.top();
        heap.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v,w] : G[u])
        {
            if(dist[u] + w < dist[v])
            {
                dist[v] = dist[u] + w;
                heap.push({dist[v],v});
            }
        }
    }
    return dist[ed] == INF ? -1 : dist[ed];
}
int bfs(int st,int ed)
{
    queue<PII> q;
    q.push({st,0});
    vis[st] = 1;
    while(q.size())
    {
        auto [u,d] = q.front();
        q.pop();
        if(u == ed) return d;
        for(auto [v,_] : G[u])
        {
            if(vis[v]) continue;
            vis[v] = 1;
            q.push({v,d+1});
        }
    }
    return -1;
}
void solve()
{
    cin >> n >> m;
    for(int i=0;i<m;i++)
    {
        int a,b,t;
        cin >> a >> b >> t;
        G[a].push_back({b,t});
        G[b].push_back({a,t});
    }
    int s,d;
    cin >> s >> d;
