typedef pair<double,int> PDI;
int n,m,t;
vector<PDI> G[M];
double dist[N];
bool vis[N];
void spfa()
{
    fill(dist+1,dist+1+n,1e18);
    queue<int> q;
    dist[1] = -1;
    q.push(1);
    vis[1] = 1;
    while(q.size())
    {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for(auto [w,v] : G[u])
        {
            if(dist[u] * w < dist[v])
            {
                dist[v] = dist[u] * w;
                if(vis[v]) continue;
                vis[v] = 1;
                q.push(v);
            }
        }
    }
}
void solve()
{
    cin >> n >> m >> t;
    for(int i=0;i<m;i++)
    {
        int u,v;
        double w;
        cin >> u >> v >> w;
        G[u].push_back({w,v});
        G[v].push_back({w,u});
    }
    spfa();
    if(dist[n] != 1e18) printf("%.8lf\n",t * -dist[n]);
    else cout << -1 << '\n'; 
}
