- **解题方法**：标签说的floyd,我兴致勃勃的点进来,结果是dp
- **遇到的问题**：dp转移不会写
- **解决方案**：
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

int n,m;
int g[M][M],dp[M][M];
char trap[M][M];
void solve()
{
    int k,p;
    cin >> n >> m >> k >> p;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            cin >> g[i][j];
        }
    for(int i=0;i<k;i++){
        int x,y,c;
        cin >> x >> y >> c;
        g[x][y] += c;
    }
    for(int i=0;i<p;i++){
        int x,y;
        char c;
        cin >> x >> y >> c;
        trap[x][y] = c;
    }
    memset(dp,0x3f,sizeof dp);
    dp[1][1] = g[1][1];
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            if(i == 1 && j == 1) continue;
            dp[i][j] = min(dp[i][j-1],dp[i-1][j]) + g[i][j];

            if(i > 2 && trap[i-2][j] == 'D')
            dp[i][j] = min(g[i-1][j] + dp[i-2][j] + g[i][j],dp[i][j]);

            if(j > 2 && trap[i][j-2] == 'R')
            dp[i][j] = min(g[i][j-1] + dp[i][j-2] + g[i][j],dp[i][j]);
        }
    }

    cout << dp[n][m] << '\n';
}
