                dist[i][j] = min(dist[i][j],dist[i][k] + dist[k][j]);
            }
        }
    }
}
void solve()
{
    cin >> n >> Q;
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<n;j++)
        {
            cin >> dist[i][j];
        }
    }
    memcpy(backup,dist,sizeof dist);
    floyd();
    int t;t = 0;
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<n;j++)
        {
            t += dist[i][j];
        }
    }
    if(t <= Q)
    {
        cout << 0;
        return;
    }
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<n;j++)
        {
            cin >> limit[i][j];
        }
    }
    memcpy(backup2,limit,sizeof limit);
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                limit[i][j] = min(limit[i][j],limit[i][k] + limit[k][j]);
            }
        }
    }
    t = 0;
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<n;j++)
        {
            t += limit[i][j];
        }
    }
    if(t > Q)
    {
        cout << -1;
        return;
    }
    memcpy(limit,backup2,sizeof backup2);
    int l = 0, r = 1e7 + 1;
    while(l < r)
    {
        memcpy(dist,backup,sizeof backup);
        int mid = l + r>> 1;
        int i = 1,cnt = 1;
        while(cnt <= mid)
        {
            if(i == n + 1) i = 1;
            for(int j=0;j<n;j++)
            {
                if(dist[i-1][j] - 1 < limit[i-1][j]) continue;
                dist[i-1][j] --;
                dist[j][i-1] --;
            }
            cnt ++;i++;
        }
        floyd();
        int total = 0;
        for(int i=0;i<n;i++)
        {
            for(int j=0;j<n;j++)
            {
                total += dist[i][j];
            }
        }
        if(total <= Q) r = mid;
        else l = mid + 1;
    }

    cout << l << '\n';
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

