int isprime(int x)
{
    if(x < 2) return 0;
    for(int i=2;i<=x/i;i++)
    {
        if(x % i == 0) return 0;
    }
    return 1;
}
void floyd()
{
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<=n;i++)
        {
