#### 题目1.[城市配送路径查询](https://www.lanqiao.cn/problems/4184/learning/)
- **解题方法**：Dijkstra
- **遇到的问题**：题目上叫用A*算法,有障碍物怎么个写估价函数啊,曼哈顿距离也用不了,只能用DIjkstra
- **解决方案**：
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e2 + 10;

typedef pair<int,PII> PIPII;
int n;
char g[M][M];
int dist[M][M];
bool vis[M][M];
int dir[4][2] = {{1,0},{0,1},{-1,0},{0,-1}};
int Dijkstra(int sx,int sy,int ex,int ey)
{
    memset(dist,0x3f,sizeof dist);
    priority_queue<PIPII,vector<PIPII>,greater<PIPII>> heap;
    heap.push({0,{sx,sy}});
    dist[sx][sy] = 0;
    while(heap.size())
    {
        auto t = heap.top();
        heap.pop();
        auto [x,y] = t.second;
        if(vis[x][y]) continue;
        vis[x][y] = 1;
        for(int i=0;i<4;i++)
        {
            int nx = x + dir[i][0];
            int ny = y + dir[i][1];
            if(x < 0 || y < 0 || x >= n || y >= n) continue;
            if(g[nx][ny] == '#') continue;
            if(dist[x][y] + 1 < dist[nx][ny])
            {
                dist[nx][ny] = dist[x][y] + 1;
                heap.push({dist[nx][ny],{nx,ny}});
            }
        } 
    }

    if(dist[ex][ey] == INF) return -1;
    return dist[ex][ey];
}
void solve()
{
    cin >> n;
    for(int i=0;i<n;i++)
        for(int j=0;j<n;j++)
            cin >> g[i][j];
    int sx,sy,ex,ey;
    cin >> sx >> sy >> ex >> ey;
    cout << Dijkstra(sx,sy,ex,ey) << '\n';
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

