constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

typedef tuple<double,int,int> PDII;

int n,m;
int p[N];
map<PII,int> mp;
int find(int x)
{
    if(p[x] != x) p[x] = find(p[x]);
    return p[x];
}
void solve()
{
    cin >> n >> m;
    vector<PII> V,G;
    int x,y;
    for(int i=0;i<n;i++)
    {
        cin >> x >> y;
        V.emplace_back(x,y);
    }
    for(int i=0;i<m;i++)
    {
        cin >> x >> y;
        G.emplace_back(x,y);
    }

    vector<PDII> vil,gem;
    auto getdis = [](int x1,int y1,int x2,int y2){
        return sqrt(pow(x1-x2,2) + pow(y1-y2,2));
    };
    int cnt = 0;
    for(auto [vx,vy] : V)
    {
        if(!mp.count({vx,vy}))
        mp.insert({{vx,vy},cnt++});
        for(auto [nx,ny] : V)
        {
            if(!mp.count({nx,ny}))
            mp.insert({{nx,ny},cnt++});
            vil.push_back({getdis(vx,vy,nx,ny),mp[{vx,vy}],mp[{nx,ny}]});
        }
    }

    for(auto [gx,gy] : G)
    {
        if(!mp.count({gx,gy}))
        mp.insert({{gx,gy},cnt++});
        for(auto [nx,ny] : V)
        {
            if(!mp.count({nx,ny}))
            mp.insert({{nx,ny},cnt++});
            gem.push_back({getdis(gx,gy,nx,ny),mp[{gx,gy}],mp[{nx,ny}]});
        }
    }

    sort(all(vil));
    sort(all(gem));


    for(int i=0;i<m+n;i++) p[i] = i;


    double res = 0;

    for(auto [w,a,b] : vil)
    {
        a = find(a) , b = find(b);
        if(a!=b)
        {
            res += w;
            p[a] = b;
        }
    }
    for(auto [w,a,b] : gem)
    {
        a = find(a) , b = find(b);
        if(a!=b)
        {
            res += w;
            p[a] = b;
        }
    }
    printf("%.2lf",res);
}
