#### 题目4.[昂贵的聘礼](https://www.xfxcy.com/p/P0246)
- **解题方法**：区间Dijkstra
- **遇到的问题**：题读错了,以为是两两之间的阶级不超过m
- **解决方案**：
```cpp:line-numbers
#include<bits/stdc++.h>
// #define int long long //memset数组为0x3f时自觉去掉
#define INF 0x3f3f3f3f
#define PII pair<int,int>
#define ULL unsigned long long
#define PIII tuple<int,int,int>
#define all(v) v.begin(), v.end()
#define debug(a) cout<<#a<<"="<<a<<endl;
using namespace std;
constexpr int N =  1 * 1e6 + 10,M = 5 * 1e3 + 10;

int n,m;
int dist[N],ranks[N];
bool vis[N];
vector<PII> G[M];
int Dijkstra(int l,int r)
{
    memset(dist,0x3f,sizeof dist);
    memset(vis,false,sizeof vis);
    priority_queue<PII,vector<PII>,greater<PII>> heap;
    heap.emplace(make_pair(0,n+1));
    dist[n+1] = 0;
    while(heap.size())
    {
        auto [d,u] = heap.top();
        heap.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v,w] : G[u])
        {
            if(dist[u] + w < dist[v] && ranks[v] >= l && ranks[v] <= r)
            {
                dist[v] = dist[u] + w;
                heap.push(make_pair(dist[v],v));
            }
        }
    }

    return dist[1];
}
void solve()
{
    cin >> m >> n;
    for(int i=1;i<=n;i++)
    {
        int P,X,T,V;
        cin >> P >> ranks[i] >> X;
        G[n+1].emplace_back(i,P);
        for(int j=0;j<X;j++)
        {
            cin >> T >> V;
            G[T].emplace_back(i,V);
        }
    }

    int ans = INF;

    for(int i=ranks[1]-m;i<=ranks[1];i++) ans = min(Dijkstra(i,i+m),ans);

    cout << ans << '\n';
}
