using namespace std;
constexpr int N =  5 * 1e4 + 10,M = 2 * 1e5 + 10;

int n,m;
int ans = INF;
int rel[10];
int dist[N][10];
bool vis[N],st[N];
vector<PII> G[M];
void Dijkstra(int id)
{
    priority_queue<PII,vector<PII>,greater<PII>> heap;
    memset(vis,false,sizeof vis);
    heap.emplace(make_pair(0,rel[id]));
    dist[rel[id]][id] = 0;
    while(heap.size())
    {
        auto [d,u] = heap.top();
        heap.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v,w] : G[u])
        {
            if(dist[u][id] + w < dist[v][id])
            {
                dist[v][id] = dist[u][id] + w;
                heap.push(make_pair(dist[v][id],v));
            }
        }
    }
}
void dfs(int u,int start,int total)
{
    if(total > ans) return;
    if(u == 5)
    {
        ans = min(ans,total);
        return;
    }
    for(int i=2;i<=6;i++)
    {
        if(st[i]) continue;
        st[i] = 1;
        dfs(u+1,i,total + dist[rel[i]][start]);
        st[i] = 0;
    }
}
void solve()
{
    cin >> n >> m;
    rel[1] = 1;
    for(int i=2;i<=6;i++) cin >> rel[i];
    for(int i=0;i<m;i++)
    {
        int x,y,t;
        cin >> x >> y >> t;
        G[x].emplace_back(y,t);
        G[y].emplace_back(x,t);
    }

    memset(dist,0x3f,sizeof dist);
    for(int i=1;i<=6;i++) Dijkstra(i);

    dfs(0,1,0);

    cout << ans;
}
signed main()
{
    ios::sync_with_stdio(0);cin.tie(nullptr),cout.tie(nullptr);
    int _=1;
    // cin>>_;
    while(_--)
    {
        solve();
    }
    return 0;
}

