#### 题目4.[孤岛营救问题](https://www.luogu.com.cn/problem/P4011)
- **解题方法**：双向BFS(线性时间复杂度) + 状压DP(记录有几把钥匙的状态)
- **解决方案**：
```cpp:line-numbers
#include <bits/stdc++.h>
// #define int long long // 自觉去掉，当需要 memset 数组为 0x3f 时使用
#define INF 0x3f3f3f3f
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 15 , M = 550;

int n,m,p,k;
int g[N][N],key[N * N];
int dist[N * N][1 << 10];
bool vis[N *  N][1 << 10];
vector<PII> G[M];
map<PII,int> mp;
void build() {
    int dir[4][2] = {{1,0},{0,1},{-1,0},{0,-1}};
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            for (int d = 0; d < 4; d++) {
                int x = i + dir[d][0];
                int y = j + dir[d][1];
                if (x <= 0 || y <= 0 || x > n || y > m) continue;
                int a = g[i][j] , b = g[x][y];
                if (!mp.count({a,b})) G[a].emplace_back(b,0);
            }
        }
    }
}
int bfs() {
    memset(dist,0x3f,sizeof dist);
    deque<PII> q;
    dist[1][0] = 0;
    q.push_back({1,0});
    while (q.size()) {
        auto [u,cur] = q.front();
        q.pop_front();
        if (vis[u][cur]) continue;
        vis[u][cur] = 1;
        if (u == n*m) return dist[u][cur];
        if (key[u]) {
            int next = cur | key[u];
            if (dist[u][next] > dist[u][cur]) {
                dist[u][next] = dist[u][cur];
                q.push_front({u,next});
            }
        }

        for (auto [v,w] : G[u]) {
            if (w && !(cur >> w - 1 & 1)) continue;
            if (dist[u][cur] + 1 < dist[v][cur]) {
                dist[v][cur] = dist[u][cur] + 1;
                q.push_back({v,cur});
            }
        }
    }

    return -1;
}
void solve() {
    cin >> n >> m >> p;

    for (int i = 1, t = 1; i <= n; i++)
        for (int j = 1;j <= m;j++)
            g[i][j] = t++;

    cin >> k;
    while (k--) {
        int x1,y1,x2,y2,c;
        cin >> x1 >> y1 >> x2 >> y2 >> c;
        int a = g[x1][y1] , b = g[x2][y2];
        mp[{a,b}] = 1;mp[{b,a}] = 1;
        if (c) G[a].emplace_back(b,c) , G[b].emplace_back(a,c);
    }

    build();

    int s;
    cin >> s;
    while (s--) {
        int x,y,c;
        cin >> x >> y >> c;
        key[g[x][y]] |= 1 << c - 1;
    }

    cout << bfs() << '\n';
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

