#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 5 * 1e3 + 10;


void solve() {
    int n;
    cin >> n;
    string a,b;
    cin >> a >> b;
    PII A,B;
    for (auto c : a) 
        if (c == '0') A.first++; 
        else A.second++;
    for (auto c : b)
        if (c == '0') B.first++;
        else B.second++;

    cout << min(A.first, B.second) + min(A.second, B.first) << '\n';
}   

