#### 题目4.[信息学奥赛一本通T1497-农场派对](https://www.dotcpp.com/oj/problem2406.html)
- **解题方法**：求出终点到所有点的最短路,再从所有起点到终点的最短路相加更新最大值
- **遇到的问题**：
- **解决方案**：
```cpp:line-numbers
#include <bits/stdc++.h>
// #define int long long // 自觉去掉，当需要 memset 数组为 0x3f 时使用
#define INF 0x3f3f3f3f
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1000 + 10, M = 2 * 100000 + 10;

int n, m, X;
int dist[N],d[N];
bool vis[N];
vector<PII> G[M];
void Spfa(int st) {
    memset(dist, 0x3f, sizeof dist);
    queue<int> q;
    dist[st] = 0;
    q.emplace(st);
    while (q.size()) {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for (auto [v, w] : G[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (vis[v]) continue;
                vis[v] = 1;
                q.emplace(v);
            }
        }
    }
}
void solve() {
    cin >> n >> m >> X;
    while (m--) {
        int a, b, t;
        cin >> a >> b >> t;
        G[a].emplace_back(b, t);
    }

    for (int i = 1; i <= n; i++) G[0].emplace_back(i, 0);


    Spfa(X);
    memcpy(d, dist, sizeof dist);

    int ans = 0;
    for (int i = 1; i <= n; i++) {
        Spfa(i);
        ans = max(ans, dist[X] + d[i]);
    }

    cout << ans << '\n';
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

