#### 题目6.[信息学奥赛一本通T1502-汽车加油行驶问题](https://www.dotcpp.com/oj/problem2411.html)
- **解题方法**：Dijkstra
- **解决方案**：
```cpp:line-numbers
#include <bits/stdc++.h>
#define int long long // 自觉去掉，当需要 memset 数组为 0x3f 时使用
#define INF 0x3f3f3f3f
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 100 + 10;

int n, k, A, B, C;
int g[M][M];
int dist[M][M][15];
int bfs() {
    memset(dist, 0x3f, sizeof dist);
    int dir[4][2] = {{1, 0}, {0, 1},{-1, 0}, {0, -1}};
    queue<PIII> q;
    q.emplace(1, 1, k);
    dist[1][1][k] = 0;
    while (q.size()) {
        auto [x, y, oil] = q.front();
        q.pop();
        if (g[x][y] == 1 && oil != k) {
            if (dist[x][y][oil] + A < dist[x][y][k]) {
                dist[x][y][k] = dist[x][y][oil] + A;
                q.emplace(x, y, k);
            }
            continue;
        }
        if (dist[x][y][oil] + A + C < dist[x][y][k]) {
            dist[x][y][k] = dist[x][y][oil] + A + C;
            q.emplace(x, y, k);
        }

        if(oil > 0) {
            for (int i = 0; i < 4; i++) {
                int nx = x + dir[i][0], ny = y + dir[i][1];
                if (nx <= 0 || ny <= 0 || nx > n || ny > n) continue;
                int w = (i == 2 || i == 3 ? B : 0);
                if (dist[x][y][oil] + w < dist[nx][ny][oil - 1]) {
                    dist[nx][ny][oil - 1] = dist[x][y][oil] + w;
                    q.emplace(nx, ny, oil - 1);
                }
            }
        }

    }

    int res = INF;
    for (int i = 0; i <= k; i++) {
        res = min(res,dist[n][n][i]);
    }

    return res;
}
void solve() {
    cin >> n >> k >> A >> B >> C;
    for(int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            cin >> g[i][j];
        }
    }

    cout << bfs() << '\n';
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

