#### 题目7.[信息学奥赛一本通T1494-Sightseeing Trip](https://www.dotcpp.com/oj/problem2403.html)
- **解题方法**：Floyd
- **遇到的问题**：会爆int
- **解决方案**：
```cpp:line-numbers
#include <bits/stdc++.h>
#define int long long // 自觉去掉，当需要 memset 数组为 0x3f 时使用
#define INF 0x3f3f3f3f
#define PII pair<int, int>
#define ULL unsigned long long
#define PIII tuple<int, int, int>
#define all(v) v.begin(), v.end()
#define debug(a) cout << #a << " = " << a << endl;
using namespace std;
constexpr int N = 1 * 1e6 + 10, M = 100 + 10;

int n, m;
int ans = INF;
int dist[M][M],path[M][M],g[M][M];
vector<int> hoop;
void getpath(int u, int v) {
    if (!path[u][v]) return;
    getpath(u, path[u][v]);
    hoop.emplace_back(path[u][v]);
    getpath(path[u][v], v);
}
void Floyd() {
    for (int k = 1; k <= n; k++) {

        for (int i = 1; i < k; i++) {
            for (int j = i + 1; j < k; j++) {
                if (ans > dist[i][j] + g[i][k] + g[k][j]) {
                    ans = dist[i][j] + g[i][k] + g[k][j];
                    hoop.clear();
                    hoop.emplace_back(i);
                    getpath(i,j);
                    hoop.emplace_back(j);
                    hoop.emplace_back(k);
                }
            }
        }

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if(dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                    path[i][j] = k;
                }
            }
        }
    }

}
void solve() {
    cin >> n >> m;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (i == j) continue;
            dist[i][j] = g[i][j] = INF;
        }
    }

    while (m--) {
        int x, y, z;
        cin >> x >> y >> z;
        dist[x][y] = dist[y][x] = g[x][y] = g[y][x] = min(dist[x][y], z);
    }

    Floyd();

    if (ans == INF) cout << "No solution." << '\n';
    else {
        for (int x : hoop) cout << x << ' ';
    }
}

signed main() {
    ios::sync_with_stdio(0); cin.tie(nullptr), cout.tie(nullptr);
    int _ = 1;
    // cin >> _;
    while (_--) {
        solve();
    }
    return 0;
}

